INSERT INTO `wp_options` VALUES (807,'sb_instagram_errors','a:10:{s:10:\"connection\";a:0:{}s:7:\"hashtag\";a:0:{}s:8:\"resizing\";a:0:{}s:15:\"database_create\";a:0:{}s:10:\"upload_dir\";a:0:{}s:8:\"accounts\";a:0:{}s:9:\"error_log\";a:1:{i:0;s:329:\"04-11 16:26:09 - Tu feed de Instagram no se ha visto en los últimos 14 días. De acuerdo con las normas de privacidad de datos de Instagram, todos los datos de este feed se eliminarán dentro de 7 días. Para evitar la eliminación automática de los datos, basta con ver el feed de Instagram en tu web en los próximos 7 días.\";}s:10:\"action_log\";a:2:{i:0;s:41:\"03-21 13:24:24 - Retesting GDPR features.\";i:1;s:43:\"04-11 16:26:09 - Deleted all platform data.\";}s:7:\"revoked\";a:0:{}s:11:\"unused_feed\";s:312:\"Tu feed de Instagram no se ha visto en los últimos 14 días. De acuerdo con las normas de privacidad de datos de Instagram, todos los datos de este feed se eliminarán dentro de 7 días. Para evitar la eliminación automática de los datos, basta con ver el feed de Instagram en tu web en los próximos 7 días.\";}','off');
