INSERT INTO `wp_options` VALUES (822,'sbi_notifications','a:4:{s:6:\"update\";i:1775924860;s:4:\"feed\";a:1:{i:0;a:9:{s:2:\"id\";i:45;s:6:\"plugin\";a:6:{i:0;s:9:\"instagram\";i:1;s:8:\"facebook\";i:2;s:7:\"twitter\";i:3;s:7:\"reviews\";i:4;s:6:\"tiktok\";i:5;s:7:\"youtube\";}s:4:\"type\";a:1:{i:0;s:4:\"free\";}s:5:\"title\";s:48:\"Add a Free WhatsApp Chat to Your Site in Minutes\";s:7:\"content\";s:541:\"Hey there! We\'re excited to share something new from the Smash Balloon team. Knowing how important direct connection is, we built WPChat. It’s the easiest way to chat with your site visitors on WhatsApp, Messenger, and Telegram, helping you provide instant, personal support. It\'s completely free to get started. The free version includes live chat for one agent via WhatsApp, Facebook Messenger or Telegram, AI-Powered Smart FAQs to automatically answer questions, and a beautiful, customizable chat widget that looks great on any device.\";s:5:\"start\";s:19:\"2025-10-30 00:00:00\";s:3:\"end\";s:19:\"2026-10-30 23:59:59\";s:5:\"image\";s:7:\"balloon\";s:4:\"btns\";a:2:{s:7:\"primary\";a:3:{s:4:\"text\";s:19:\"Try WPChat for Free\";s:3:\"url\";s:181:\"https://wpchat.com/how-to-get-free-whatsapp-chat-plugin-wordpress/?utm_source={plugin}-free&utm_medium=plugin-dashboard-notices&utm_campaign=wpchatlaunch&utm_content=try-wpchat-free\";s:4:\"attr\";a:1:{i:0;s:11:\"targetblank\";}}s:9:\"secondary\";a:3:{s:4:\"text\";s:17:\"Add Free Chat Now\";s:3:\"url\";s:179:\"https://wpchat.com/how-to-get-free-whatsapp-chat-plugin-wordpress/?utm_source={plugin}-free&utm_medium=plugin-dashboard-notices&utm_campaign=wpchatlaunch&utm_content=add-free-chat\";s:4:\"attr\";a:1:{i:0;s:11:\"targetblank\";}}}}}s:6:\"events\";a:0:{}s:9:\"dismissed\";a:0:{}}','auto');
